import React, { useEffect, useState } from "react";
import { signOut } from "firebase/auth";
import { auth, db } from "../firebase";
import { useNavigate } from "react-router-dom";
import { collection, getDocs, query, where } from "firebase/firestore";

const Dashboard = ({ user }) => {
  const [batches, setBatches] = useState([]);
  const [status, setStatus] = useState("Unavailable");
  const navigate = useNavigate();

  useEffect(() => {
    const fetchBatches = async () => {
      try {
        if (!user?.uid) return;

        const q = query(
          collection(db, "print_batches"),
          where("shopId", "==", user.uid)
        );
        const querySnapshot = await getDocs(q);

        const fetchedBatches = [];
        querySnapshot.forEach((doc) => {
          fetchedBatches.push({ id: doc.id, ...doc.data() });
        });

        setBatches(fetchedBatches);
      } catch (error) {
        console.error("Error fetching batches:", error);
      }
    };

    fetchBatches();
  }, [user]);

  return (
    <div className="min-h-screen bg-gray-100 p-4">
      <div className="max-w-4xl mx-auto bg-white shadow-md rounded p-6">
        <div className="flex justify-between items-center mb-4">
          <h2 className="text-2xl font-bold">📋 Print Orders</h2>
          <div className="flex gap-2">
            <button
              onClick={() => navigate("/set-rates")}
              className="bg-blue-500 text-white px-4 py-2 rounded"
            >
              Set Rates
            </button>
            <button
              onClick={() => signOut(auth)}
              className="bg-red-500 text-white px-4 py-2 rounded"
            >
              Logout
            </button>
          </div>
        </div>

        <div className="mb-4">
          <label className="block mb-1 font-medium">Shop Status:</label>
          <select
            value={status}
            onChange={(e) => setStatus(e.target.value)}
            className="border border-gray-300 rounded px-4 py-2 w-full"
          >
            <option value="Available">Available ✅</option>
            <option value="Unavailable">Unavailable ❌</option>
          </select>
        </div>

        {batches.length === 0 ? (
          <p className="text-gray-500">No print orders yet.</p>
        ) : (
          <div className="space-y-4">
            {batches.map((batch) => (
              <div
                key={batch.id}
                className="border rounded p-4 bg-gray-50 shadow-sm"
              >
                <h3 className="font-semibold text-lg mb-2">
                  📄 File: {batch.fileName}
                </h3>
                <p><strong>Prints:</strong> {batch.totalPrints}</p>
                <p><strong>Pages:</strong> {batch.totalPages}</p>
                <p><strong>Sheets:</strong> {batch.totalSheets}</p>
                <p><strong>Price:</strong> ₹{batch.price}</p>
                <a
                  href={batch.fileUrl}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="inline-block mt-2 text-blue-600 hover:underline"
                >
                  ⬇️ Download File
                </a>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default Dashboard;
